B.XG=new A.dy("burdenedLaborer",B.bD,"\ub4f1\uc9d0\uafbc","\ud83c\udf92","HP\uac00 \ub192\uace0 \ub290\ub9ac\uc9c0\ub9cc \uafb8\uc900\ud788 \ubc00\uace0 \ub4e4\uc5b4\uc624\ub294 \uc6d0\ud63c. \uc9c0\uac8c\uc5d0 \ud55c\uc744 \uac00\ub4dd \uc9ca\uc5b4\uc9c0\uace0 \uc788\ub2e4.","\ub4f1\uc9d0\uafbc\uc740 \uc591\ubc18\uc758 \ubb34\uac70\uc6b4 \uc9d0\uc744 \ub300\uc2e0 \uc838\uc8fc\ub2e4 \ud5c8\ub9ac\uac00 \uaebe\uc5ec \uc8fd\uc740 \ub178\ube44\uc600\ub2e4. \uadf8 \uc9d0 \uc18d\uc5d0\ub294 \uc0ac\uc2e4 \uc591\ubc18\uc774 \ube7c\ub3cc\ub9b0 \uad00\uace1\uc774 \ub4e4\uc5b4\uc788\uc5c8\ub2e4.","\ub4f1\uc9d0\uafbc\uc758 \uc9c0\uac8c\ub97c \ub0b4\ub824\ub193\uac8c \ud574\uc8fc\uba74, \uadf8 \uc548\uc5d0\uc11c \uc783\uc5b4\ubc84\ub9b0 \ubcf4\ubb3c\uc774 \uc0b0\ub354\ubbf8\ucc98\ub7fc \uc3df\uc544\uc9c4\ub2e4\ub294 \uc804\uc124\uc774 \ub0b4\ub824\uc628\ub2e4.",1,10,100,1000,1,2,5,10)
B.XH=new A.dy("world_palace",B.eB,"\uc655\uad81\uc758 \uadf8\ub9bc\uc790","\ud83c\udfef","\uad8c\ub825\uc5d0 \ubb3c\ub4e0 \uc655\uad81. \uc554\uc0b4\uacfc \uc74c\ubaa8\uac00 \ub09c\ubb34\ud558\ub294 \uc800\uc8fc\ubc1b\uc740 \uad81.","\uc655\uad81\uc758 \uc9c0\ud558\uc5d0\ub294 \uc655\uc774 \ucc98\ud615\ud55c \ucda9\uc2e0\ub4e4\uc758 \ubaa9\uc774 \ubd09\uc778\ub418\uc5b4 \uc788\ub2e4. \ub9e4\ub144 \ud55c\uc2dd\ub0a0\uc774\uba74 \uc774 \ubaa9\ub4e4\uc774 \uc9c4\uc2e4\uc744 \uc678\uce5c\ub2e4.",'\uc655\uad81\uc5d0 \uc804\ud574\uc9c0\ub294 \uae08\uae30 \u2014 "\uc625\uc88c\uc5d0 \uc549\uc740 \uc790\ub294 \ubc18\ub4dc\uc2dc \uadf8\ub9bc\uc790\ub97c \ubc14\uafbc\ub2e4." \uc774 \ub9d0\uc758 \uc9c4\uc9dc \uc758\ubbf8\ub97c \uc544\ub294 \uc790\ub294 \uc655\uad81\uc5d0\uc11c \uc0b4\uc544\ub098\uc62c \uc218 \uc5c6\ub2e4.',0,1,10,50,2,5,10,20)
B.XI=new A.dy("world_forest",B.eB,"\ud1b5\uace1\ud558\ub294 \uc232","\ud83c\udf32","\ubc24\ub9c8\ub2e4 \ud1b5\uace1 \uc18c\ub9ac\uac00 \uc6b8\ub9ac\ub294 \uc232. \uc0b0\uc9d0\uc2b9\uacfc \uc694\uad34\uac00 \uc9c0\ubc30\ud558\ub294 \uc704\ud5d8 \uc9c0\ub300.","\ud1b5\uace1\ud558\ub294 \uc232\uc758 \ub098\ubb34\ub4e4\uc740 \uc0ac\uc2e4 \uc0b4\uc544\uc788\ub2e4. \ubc8c\ubaa9\uc73c\ub85c \uc798\ub9b0 \ub098\ubb34\uc758 \uadf8\ub8e8\ud130\uae30\uc5d0\uc11c \ub4e4\ub824\uc624\ub294 \uc6b8\uc74c\uc18c\ub9ac\uac00 \uc232 \uc804\uccb4\uc5d0 \uba54\uc544\ub9ac\uce5c\ub2e4.",'\uc232\uc758 \uac00\uc7a5 \uae4a\uc740 \uacf3\uc5d0\ub294 "\uccab \ubc88\uc9f8 \ub098\ubb34"\uac00 \uc788\ub2e4 \ud55c\ub2e4. \uc774 \ub098\ubb34\ub97c \ucc3e\ub294 \uc790\uc5d0\uac8c \uc232\uc740 \ubaa8\ub4e0 \ube44\ubc00\uc744 \uc18d\uc0ad\uc5ec\uc900\ub2e4. \ub2e4\ub9cc \uadf8 \ube44\ubc00\uc744 \ubc1c\uc124\ud558\uba74 \ub098\ubb34\uac00 \ub418\uc5b4 \uc601\uc6d0\ud788 \uc232\uc5d0 \uac07\ud78c\ub2e4.',0,1,10,50,2,5,10,20)
B.XJ=new A.dy("world_market",B.eB,"\uad76\uc8fc\ub9b0 \uc790\ub4e4\uc758 \uc7a5\ud130","\ud83c\udfda\ufe0f","\ub300\uae30\uadfc\uc73c\ub85c \ubb34\ub108\uc9c4 \uc870\uc120 \uc7a5\ud130. \uad76\uc8fc\ub9b0 \uc6d0\ud63c\ub4e4\uc774 \ub9c8\uc9c0\ub9c9 \uc628\uae30\ub97c \ucc3e\uc544 \ub5a0\ub3c8\ub2e4.","\uc774 \uc7a5\ud130\ub294 \uc2e4\uc740 \uad00\uc758 \uc2dd\ub7c9 \ucc3d\uace0\ub97c \ubd88\ud0dc\uc6b4 \ud0d0\uad00\uc624\ub9ac\uc758 \ud589\uc801\uc774 \ub0b3\uc740 \ube44\uadf9\uc758 \ud604\uc7a5\uc774\ub2e4. \uc7a5\ud130\uc758 \ubaa8\ub4e0 \uc6d0\ud63c\uc740 \uadf8 \ud55c \uc0ac\ub78c\uc758 \ud0d0\uc695\uc774 \ub9cc\ub4e0 \uac83.",'\uc7a5\ud130 \ud55c\uac00\uc6b4\ub370 \uc138\uc6cc\uc9c4 \uc19f\ub300\uc5d0\ub294 "\ub2e4\uc2dc\ub294 \uad76\uae30\uc9c0 \ub9c8\ub77c"\ub294 \uae30\ub3c4\uac00 \uc0c8\uaca8\uc838 \uc788\ub2e4. \uc774 \uc19f\ub300\uac00 \ube5b\ub098\ub294 \ub0a0, \uc6d0\ud63c\ub4e4\uc740 \uc7a0\uae50\uc774\ub098\ub9c8 \ub530\ub73b\ud55c \ubc25 \ub0c4\uc0c8\ub97c \ub9e1\uc744 \uc218 \uc788\ub2e4 \ud55c\ub2e4.',0,1,10,50,2,5,10,20)
B.XK=new A.dy("maidenGhost",B.bD,"\ucc98\ub140\uadc0\uc2e0","\ud83d\udc70","\uc2dc\uc9d1\uc744 \uac00\uc9c0 \ubabb\ud558\uace0 \uc8fd\uc740 \ucc98\ub140\uc758 \uc138 \uc601\ud63c\uc774 \ud55c\uc774 \ub418\uc5b4 \ub5a0\ub3c8\ub2e4. \ube60\ub974\uace0 \ud68c\ud53c\uc728\uc774 \ub192\ub2e4.","\uc774 \ucc98\ub140\uadc0\uc2e0\uc740 \uc2e4\uc740 \uc0ac\ub610\uc758 \uc544\ub4e4\uc5d0\uac8c \uac81\ud0c8\ub2f9\ud55c \ub4a4 \uc218\uce58\uc2a4\ub7ec\uc6c0\uc5d0 \ud22c\uc2e0\ud55c \uaddc\uc218\uc600\ub2e4. \uadf8 \uc544\ub4e4\uc740 \ubc8c\uc744 \ubc1b\uc9c0 \uc54a\uc558\uace0, \ucc98\ub140\uc758 \ud55c\uc740 \uc601\uc6d0\ud788 \ud480\ub9ac\uc9c0 \uc54a\uc558\ub2e4.","\ub09c\uac04 \uc704\uc5d0\uc11c \ud540 \ubd89\uc740 \ub3d9\ubc31\uaf43\uc740 \ucc98\ub140\uadc0\uc2e0\uc758 \ub208\ubb3c\uc774 \uc2a4\uba70\ub4e0 \uac83\uc774\ub77c \ud55c\ub2e4. \uc774 \uaf43\uc744 \uaebe\uc73c\uba74 \ubc18\ub4dc\uc2dc \ubd88\ud589\uc774 \ucc3e\uc544\uc628\ub2e4.",1,10,100,1000,1,2,5,10)
