B.XN=new A.dy("world_faceless",B.eB,"\uc5bc\uad74 \uc5c6\ub294 \uc232","\ud83c\udfad","\uc815\uccb4\ub97c \uc783\uc740 \uc601\ud63c\ub4e4\uc774 \ub5a0\ub3c4\ub294 \uc548\uac1c\uc758 \uc232. \ub204\uad6c\uc758 \uc5bc\uad74\uc778\uc9c0 \uc54c \uc218 \uc5c6\ub294 \uadf8\ub9bc\uc790\ub4e4\uc774 \ubc30\ud68c\ud55c\ub2e4.","\uc774 \uc232\uc740 \ud55c\uc591\uc758 \uc5ed\uc801 \uac00\ubb38\uc774 \uc0bc\uc871\uc744 \uba78\ud558\uba70 \uc0dd\uae34 \uacf3\uc774\ub2e4. \uc774\ub984\uc774 \uc9c0\uc6cc\uc9c0\uace0 \uc5bc\uad74\uc774 \uc9c0\uc6cc\uc9c4 \uc790\ub4e4\uc758 \ud55c\uc774 \uc548\uac1c\uac00 \ub418\uc5b4 \uc232\uc744 \ub36e\uc5c8\ub2e4.","\uc5bc\uad74 \uc5c6\ub294 \uc232\uc5d0\uc11c \uc790\uc2e0\uc758 \uc9c4\uc9dc \uc5bc\uad74\uc744 \ub9c8\uc8fc\ud558\uba74, \uadf8\uac83\uc774 \uac00\uc7a5 \ub450\ub824\uc6b4 \uc801\uc774 \ub41c\ub2e4 \ud55c\ub2e4. \uadf8\ub798\uc11c \uc774 \uc232\uc5d0 \ub4e4\uc5b4\uac04 \uc790\ub294 \ub208\uc744 \uac10\uace0 \uac78\uc5b4\uc57c \ud55c\ub2e4.",0,1,10,50,2,5,10,20)
B.XO=new A.dy("bossOgreLord",B.bD,"\ud83d\udd25 \ub3c4\uae68\ube44 \ub450\ubaa9","\ud83d\udc79","\uc7a5\ud130\ub97c \uc9c0\ubc30\ud558\ub294 \uac70\ub300\ud55c \ub3c4\uae68\ube44. \ubc29\ub9dd\uc774 \ud55c \ubc88\uc774\uba74 \uc0b0\uc774 \ubb34\ub108\uc9c4\ub2e4.","\ub3c4\uae68\ube44 \ub450\ubaa9\uc740 \uc6d0\ub798 \uc7a5\ud130\ub97c \uc9c0\ud0a4\ub358 \uc218\ud638\uc2e0\uc774\uc5c8\ub2e4. \uadf8\ub7ec\ub098 \uc778\uac04\uc758 \ud0d0\uc695\uc744 \ub108\ubb34 \ub9ce\uc774 \ubcf4\uace0 \ud0c0\ub77d\ud558\uc5ec, \uc9c0\ud0a4\ub358 \uac83\uc744 \ubd80\uc218\uae30 \uc2dc\uc791\ud588\ub2e4.","\ub3c4\uae68\ube44 \ub450\ubaa9\uc758 \ubc29\ub9dd\uc774\ub294 \uc0ac\uc2e4 \ub450 \uac1c\uac00 \ud55c \uc30d\uc774\ub2e4. \uae08 \ub098\uc624\ub294 \ubc29\ub9dd\uc774\uc640 \uae08 \uc0ac\ub77c\uc9c0\ub294 \ubc29\ub9dd\uc774. \ud0d0\uc695\uc5d0 \ub208\uc774 \uba3c \uc778\uac04\ub4e4\uc740 \ud56d\uc0c1 \uc798\ubabb\ub41c \ucabd\uc744 \uace0\ub978\ub2e4.",1,3,30,100,3,5,10,25)
B.XP=new A.dy("bossMountainLord",B.bD,"\ud83d\udd25 \uc0b0\uad70 \ub300\uc655","\ud83d\udc2f","\uc232\uc744 \uc9c0\ubc30\ud558\ub294 \ucd08\uc790\uc5f0\uc801 \ud638\ub791\uc774. \ud3ec\ud6a8 \ud55c \ubc88\uc5d0 \ubc14\uc704\uac00 \uac08\ub77c\uc9c4\ub2e4.","\uc0b0\uad70 \ub300\uc655\uc740 \uc6d0\ub798 \uc0b0\uc2e0\ub839\uc774 \ud0c0\uace0 \ub2e4\ub2c8\ub358 \uc131\uc218\uc600\uc73c\ub098, \uc0b0\uc2e0\uc774 \uc7a0\ub4e0 \uc0ac\uc774 \uad8c\uc88c\ub97c \ucc2c\ud0c8\ud588\ub2e4. \uc774\uc81c \uc0b0 \uc790\uccb4\uac00 \uadf8\uc758 \uc601\uc5ed\uc774\ub2e4.","\uc0b0\uad70 \ub300\uc655\uc758 \uc774\ube68 \ud558\ub098\uc5d0 \uc0b0\uc2e0\ub839\uc758 \ud798 \ud55c \uc870\uac01\uc774 \uae43\ub4e4\uc5b4 \uc788\ub2e4. \uc774\ub97c \ubaa8\ub450 \ubaa8\uc73c\uba74 \uc7a0\ub4e0 \uc0b0\uc2e0\uc744 \uae68\uc6b8 \uc218 \uc788\ub2e4 \ud558\uc5ec \ub9ce\uc740 \uc6a9\uc0ac\uac00 \ub3c4\uc804\ud588\uc73c\ub098, \ub3cc\uc544\uc628 \uc790\ub294 \uc5c6\ub2e4.",1,3,30,100,3,5,10,25)
B.XQ=new A.dy("fireDog",B.bD,"\ubd88\uac1c","\ud83d\udd25","\uc785\uc5d0\uc11c \ubd88\uc744 \ubfdc\ub294 \uc124\ud654 \uc18d\uc758 \uc9d0\uc2b9. \uc9c0\ub098\uac04 \uc790\ub9ac\uc5d0 \ubd88\uae38\uc744 \ub0a8\uae34\ub2e4.","\ubd88\uac1c\ub294 \uc6d0\ub798 \ud574\uc640 \ub2ec\uc744 \ucad3\ub358 \ucc9c\uc0c1\uc758 \ub9f9\uc218\uc600\uc73c\ub098, \ubc88\ubc88\uc774 \uc2e4\ud328\ud558\uc5ec \uc9c0\uc0c1\uc73c\ub85c \ucad3\uaca8\ub0ac\ub2e4. \uadf8 \ubd84\ub178\uac00 \uc785\uc5d0\uc11c \ubd88\uc774 \ub418\uc5b4 \ud130\uc838 \ub098\uc628\ub2e4.","\ub9cc\uc57d \ubd88\uac1c\uac00 \ud574\ub97c \uc0bc\ud0a4\ub294 \ub370 \uc131\uacf5\ud55c\ub2e4\uba74, \uc138\uc0c1\uc740 \uc601\uc6d0\ud55c \ubc24\uc774 \ub41c\ub2e4. \uc124\ud654 \uc18d \ud604\uc790\ub4e4\uc740 \uc774\ub97c \ub9c9\uae30 \uc704\ud574 \uc9d5\uacfc \ubd81\uc744 \uce58\uba70 \ubd88\uac1c\ub97c \ucad3\uc558\ub2e4 \ud55c\ub2e4.",1,10,100,1000,1,2,5,10)
B.XR=new A.dy("strawShoeSpirit",B.bD,"\uc9da\uc2e0\uc601\uac10","\ud83d\udc74","\ub0a1\uc740 \uc9da\uc2e0\uc744 \uc2e0\uace0 \ub290\ub9bf\ub290\ub9bf \ub2e4\uac00\uc624\ub294 \ub178\uc778\uc758 \uc601\ud63c. \uc9c0\ud321\uc774\ub85c \ud0c0\uc6cc\ub97c \ub450\ub4e4\uae34\ub2e4.","\uc9da\uc2e0\uc601\uac10\uc740 \uc0dd\uc804 \uc7a5\ud130\uae4c\uc9c0 \ubc31 \ub9ac\ub97c \uac78\uc5b4 \uc57d\uc744 \uad6c\ud558\ub7ec \ub098\uc130\uc73c\ub098, \uacb0\uad6d \ub3c4\ucc29\ud558\uc9c0 \ubabb\ud558\uace0 \uae38 \uc704\uc5d0\uc11c \uba48\ucd94\uc5c8\ub2e4. \uadf8\uc758 \uc9da\uc2e0\ub9cc\uc774 \uae38 \uc704\uc5d0 \ub0a8\uc558\ub2e4.","\uc9da\uc2e0\uc601\uac10\uc758 \uc9da\uc2e0 \ud55c \ucf24\ub808\ub97c \ucc3e\uc73c\uba74 \uc5b4\ub5a4 \uae38\uc774\ub4e0 \ubbf8\ub044\ub7ec\uc9c0\uc9c0 \uc54a\ub294 \uc2e0\ube44\ud55c \ud798\uc774 \uae43\ub4e0\ub2e4\uace0 \uc804\ud574\uc9c4\ub2e4.",1,10,100,1000,1,2,5,10)
B.XS=new A.dy("eggGhost",B.bD,"\ub2ec\uac40\uadc0\uc2e0","\ud83e\udd5a","\uc774\ubaa9\uad6c\ube44\uac00 \uc5c6\ub294 \ud770 \uc5bc\uad74\uc758 \uadc0\uc2e0. \ubcf4\uba74 \uacf5\ud3ec\uc5d0 \uc9c8\ub824 \ud0c0\uc6cc\uac00 \uc7a0\uc2dc \uae30\ub2a5\uc744 \uba48\ucd98\ub2e4.","\ub2ec\uac40\uadc0\uc2e0\uc758 \uc815\uccb4\ub294 \uc774\ub984\uc870\ucc28 \uae30\ub85d\ub418\uc9c0 \uc54a\uc740 \uc775\uba85\uc758 \uc6d0\ud63c\ub4e4. \uc774\ub984\uc774 \uc5c6\uae30\uc5d0 \uc5bc\uad74\ub3c4 \uc5c6\uace0, \uc800\uc2b9\uc5d0\uc11c\ub3c4 \ubc1b\uc544\uc8fc\uc9c0 \uc54a\uc544 \uc774\uc2b9\uc744 \ub5a0\ub3cc\uac8c \ub418\uc5c8\ub2e4.","\ub2ec\uac40\uadc0\uc2e0\uc5d0\uac8c \uc9c4\uc2ec\uc73c\ub85c \uc774\ub984\uc744 \uc9c0\uc5b4\uc8fc\uba74, \ud750\ub9bf\ud588\ub358 \uc5bc\uad74\uc5d0 \ubbf8\uc18c\uac00 \ud53c\uc5b4\uc624\ub978\ub2e4 \ud55c\ub2e4. \uadf8\ub9ac\uace0 \uac10\uc0ac\uc758 \ud45c\uc2dc\ub85c \uc228\uaca8\ub454 \ubcf4\ubb3c\uc744 \uc54c\ub824\uc900\ub2e4.",1,10,100,1000,1,2,5,10)
B.XT=new A.dy("hero_bari",B.eA,"\ubc14\ub9ac","\ud83c\udf38","\ubc84\ub9bc\ubc1b\uc740 \uacf5\uc8fc\uac00 \ubb34\ub2f9\uc774 \ub41c \uc874\uc7ac. \uce58\uc720\uc640 \ubd80\ud65c\uc758 \ud798\uc744 \uac00\uc84c\ub2e4.","\ubc14\ub9ac\ub370\uae30 \uc124\ud654\uc5d0 \ub530\ub974\uba74, \ubc14\ub9ac\ub294 \uc544\ud649 \ubc88\uc9f8\ub85c \ud0dc\uc5b4\ub09c \ub538\uc774\ub77c \ubc84\ub824\uc84c\uc73c\ub098, \uc8fd\uc740 \ubd80\ubaa8\ub97c \uc0b4\ub9ac\uae30 \uc704\ud574 \uc800\uc2b9\uae4c\uc9c0 \uc57d\uc218\ub97c \uad6c\ud558\ub7ec \uac14\ub2e4.","\ubc14\ub9ac\uac00 \uc800\uc2b9\uc5d0\uc11c \uac00\uc838\uc628 \uc57d\uc218\ub294 \uc138 \uac00\uc9c0\uc774\ub2e4. \ud558\ub098\ub294 \uc0b4\ub9ac\ub294 \ubb3c, \ud558\ub098\ub294 \uc78a\uac8c \ud558\ub294 \ubb3c, \uadf8\ub9ac\uace0 \ub9c8\uc9c0\ub9c9\uc740 \uae30\uc5b5\ud558\uac8c \ud558\ub294 \ubb3c. \ubc14\ub9ac\ub294 \ud56d\uc0c1 \uc138 \ubc88\uc9f8 \ubb3c\ubd80\ud130 \uc4f4\ub2e4.",0,5,50,500,1,2,5,10)
B.XU=new A.dy("hungryGhost",B.bD,"\ud5c8\uae30\uadc0","\ud83d\udc7b","\uad76\uc8fc\ub9bc \uc18d\uc5d0 \uc8fd\uc5b4\uac04 \uc6d0\ud63c. \uc785\uc5d0\uc11c \ub04a\uc784\uc5c6\uc774 \ucc28\uac00\uc6b4 \uae30\uc6b4\uc774 \ud758\ub7ec\ub098\uc628\ub2e4.","\ud5c8\uae30\uadc0\ub294 \uc2e4\uc740 \ub300\uae30\uadfc \uc2dc\uae30 \uad00\uc758 \uad6c\ud638\ub97c \ubc1b\uc9c0 \ubabb\ud55c \ub9cc\ubc31\uc131\uc774\uc5c8\ub2e4. \uadf8\ub4e4\uc758 \ud55c\uc740 \uc0b4\uc544\uc788\ub294 \uc790\uc758 \ub530\ub73b\ud55c \ubc25 \ub0c4\uc0c8\ub97c \ub9e1\uc744 \ub54c\ub9c8\ub2e4 \ub418\uc0b4\uc544\ub09c\ub2e4.","\uc804\uc124\uc5d0 \uc758\ud558\uba74, \ud5c8\uae30\uadc0 \ucc9c \ub9c8\ub9ac\ub97c \ud574\uc6d0\ud558\uba74 \uadf8 \uc911 \ud55c \uc601\ud63c\uc774 \uac10\uc0ac\uc758 \ub73b\uc73c\ub85c \ud669\uae08 \uc218\uc800\ub97c \ub0a8\uae34\ub2e4 \ud558\uc5ec, \uc7a5\ud130\uc758 \uc0c1\uc778\ub4e4\uc740 \ubc24\ub9c8\ub2e4 \uacf5\uc591\uc744 \uc62c\ub838\ub2e4\uace0 \ud55c\ub2e4.",1,10,100,1000,1,2,5,10)
B.XV=new A.dy("hero_miho",B.eA,"\ubbf8\ud638","\ud83e\udd8a","\uad6c\ubbf8\ud638\uc758 \ud6c4\uc608. \uc5ec\uc758\uc8fc\uc758 \ud798\uc73c\ub85c \uac15\ub825\ud55c \ub9c8\ubc95 \uacf5\uaca9\uc744 \ub0a0\ub9b0\ub2e4.","\ubbf8\ud638\ub294 \uc5b4\uba38\ub2c8 \uc5ec\uc6b0\uac00 \uc778\uac04\uc774 \ub418\ub824\ub2e4 \uc2e4\ud328\ud55c \ud55c\uc744 \ubb3c\ub824\ubc1b\uc558\ub2e4. \uadf8\ub7ec\ub098 \ubbf8\ud638\ub294 \ub2ec\ub77c \u2014 \uc778\uac04\uc744 \uc0ac\ub0e5\ud558\ub294 \ub300\uc2e0 \uc778\uac04\uacfc \ud568\uaed8 \uc2f8\uc6b0\uae30\ub85c \ud588\ub2e4.",'\ubbf8\ud638\uc758 \uaf2c\ub9ac \uc544\ud649 \uac1c\uc5d0\ub294 \uac01\uac01 \ub2e4\ub978 \uac10\uc815\uc774 \uae43\ub4e4\uc5b4 \uc788\ub2e4. \ub9c8\uc9c0\ub9c9 \uc544\ud649 \ubc88\uc9f8 \uaf2c\ub9ac\uc5d0 \uae43\ub4e0 \uac10\uc815\uc740 "\uc0ac\ub791"\uc774\ub2e4. \uc774 \uaf2c\ub9ac\uac00 \ube5b\ub0a0 \ub54c \ubbf8\ud638\ub294 \uac00\uc7a5 \uac15\ud574\uc9c4\ub2e4.',0,5,50,500,1,2,5,10)
B.XW=new A.dy("hero_gangrim",B.eA,"\uac15\ub9bc","\ud83d\udc80","\uc800\uc2b9\ucc28\uc0ac. \uc8fd\uc740 \uc790\uc758 \uc601\ud63c\uc744 \uc548\ub0b4\ud558\ub294 \uac83\uc774 \ubcf8\uc5c5\uc774\uc9c0\ub9cc, \uc0ac\uc815\uc774 \uc788\uc5b4 \uc774\uc2b9\uc5d0 \ud30c\uacac\ub418\uc5c8\ub2e4.","\uac15\ub9bc\uc740 \uc6d0\ub798 \uc778\uac04\uc774\uc5c8\ub2e4. \uc5fc\ub77c\ub300\uc655\uc758 \uc2dc\ud5d8\uc5d0 \ud569\uaca9\ud558\uc5ec \ucc28\uc0ac\uac00 \ub41c \ucd5c\ucd08\uc758 \uc778\uac04\uc73c\ub85c, \uadf8\ub798\uc11c \ub204\uad6c\ubcf4\ub2e4 \uc778\uac04\uc758 \ud55c\uc744 \uc798 \uc774\ud574\ud55c\ub2e4.","\uac15\ub9bc\uc774 \ucc28\uc0ac\uac00 \ub41c \uc9c4\uc9dc \uc774\uc720\ub294 \uc0ac\ub791\ud558\ub294 \uc0ac\ub78c\uc758 \ud63c\uc744 \ub418\ucc3e\uae30 \uc704\ud574\uc11c\uc600\ub2e4. \ud558\uc9c0\ub9cc \ucc28\uc0ac\uc758 \uaddc\uc728\uc5d0 \uc758\ud574 \uadf8 \ud63c\uc744 \ub9cc\ub0a0 \uc218 \uc5c6\uac8c \ub418\uc5c8\uace0, \uc774\uac83\uc774 \uac15\ub9bc\uc758 \uc601\uc6d0\ud55c \ud55c\uc774\ub2e4.",0,5,50,500,1,2,5,10)
B.XX=new A.dy("world_death",B.eB,"\uc800\uc2b9\uc758 \ubb38\ud131","\u26e9\ufe0f","\uc774\uc2b9\uacfc \uc800\uc2b9\uc758 \uacbd\uacc4. \uc774\uacf3\uc744 \ub118\uc73c\uba74 \uc0b4\uc544\uc11c \ub3cc\uc544\uc62c \uc218 \uc5c6\ub2e4.","\uc800\uc2b9\uc758 \ubb38\ud131\uc5d0\ub294 \uc138\uc904\ubc14\ub9ac(\uc138 \uad00\ubb38\uc758 \ud30c\uc218\uafbc)\uac00 \uc9c0\ud0a4\uace0 \uc788\ub2e4. \uccab \ubc88\uc9f8\ub294 \uacfc\uac70\ub97c, \ub450 \ubc88\uc9f8\ub294 \ud604\uc7ac\ub97c, \uc138 \ubc88\uc9f8\ub294 \ubbf8\ub798\ub97c \uc2ec\ud310\ud55c\ub2e4.",'\ubc14\ub9ac\ub370\uae30\uac00 \uc774 \ubb38\ud131\uc744 \ub118\uc5c8\uc744 \ub54c, \ubb38\uc9c0\uae30\ub294 \ubb3c\uc5c8\ub2e4 \u2014 "\uc0b4\uc544 \ub3cc\uc544\uac00\uba74 \ubb34\uc5c7\uc744 \ud558\uaca0\ub290\ub0d0?" \ubc14\ub9ac\ub294 \ub2f5\ud588\ub2e4 \u2014 "\ubc84\ub9b0 \uc790\ub97c \uc6a9\uc11c\ud558\uaca0\ub2e4." \uc774 \ub300\ub2f5\uc774 \ubb38\ud131\uc744 \uc5f4\uc5c8\ub2e4.',0,1,10,50,2,5,10,20)
